import React from 'react';

const Introduction = () => {
  return (
    <section
      id="Introduction"
      className="min-h-screen flex items-center px-5 pt-24 relative"
      style={{
        fontFamily: "'Orbitron', sans-serif",
        background:
          'linear-gradient(rgba(13,110,253,0.25), rgba(10,25,47,0.9)), url(/images/background-image.jpg) no-repeat center center / cover',
      }}
    >
      <span
        aria-hidden="true"
        style={{
          position: 'absolute',
          top: '15%',
          right: '8%',
          fontSize: '96px',
          opacity: 0.05,
          color: '#fff',
          whiteSpace: 'pre-line',
        }}
      >
        ✕{"\n"}○{"\n"}□{"\n"}△
      </span>

      <div className="flex flex-col md:flex-row items-center justify-between w-full max-w-5xl mx-auto gap-12">
        <div className="flex-1">
          <p style={{ color: '#0d6efd', letterSpacing: '4px' }} className="text-xs font-bold mb-3">
            ✕ PLAYER ONE
          </p>

          <h1 className="text-white font-bold text-4xl md:text-5xl">
            ALIHAKIM M. DIMACALING
          </h1>

          <p className="text-gray-300 italic text-lg mt-3">
            University Student | Game Enthusiast | Aspiring IT Professional
          </p>

          <p className="text-gray-400 mt-4">
            Hi! I am currently pursuing a Bachelor's Degree in Information Technology majoring in Web Technology.
          </p>

          <div className="flex gap-4 mt-6">
            {[
              { label: 'Projects', href: '#Projects' },
              { label: 'Contact', href: '#Contact' },
            ].map((b) => (
              <a
                key={b.label}
                href={b.href}
                style={{
                  background: '#0d6efd',
                  color: '#fff',
                  padding: '8px 18px',
                  borderRadius: '6px',
                  textDecoration: 'none',
                  fontWeight: 'bold',
                }}
              >
                {b.label}
              </a>
            ))}
          </div>
        </div>

        <div style={{ position: 'relative' }}>
          <div
            style={{
              position: 'absolute',
              inset: '-10px',
              borderRadius: '50%',
              border: '2px solid #0d6efd',
              boxShadow: '0 0 25px rgba(13,110,253,0.5)',
            }}
          />
          <img
            src="/images/portrait-image.png"
            alt="Portrait"
            style={{
              width: '250px',
              height: '250px',
              borderRadius: '50%',
              border: '4px solid #0d6efd',
            }}
          />
        </div>
      </div>
    </section>
  );
};

export default Introduction;
